#include <stdio.h>
#include <math.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    const double SQRT2 = sqrt(2.0);
    const double SQRT3 = sqrt(3.0);
    while (T--) {
        long long i, k, s;
        double a_i, b_i;
        scanf("%lld %lld %lld", &i, &k, &s);
        scanf("%lf %lf", &a_i, &b_i);
        long long diff = k - i;
        double a_k = a_i * pow(SQRT2, (double)diff);
        double b_k = b_i * pow(SQRT3, (double)diff);
        double Q = (a_k + b_k) / pow(2.0, (double)s);
        printf("%.5f\n", Q);
    }
    return 0;
}

