code.Java:
import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        final double SQRT2 = Math.sqrt(2.0);
        final double SQRT3 = Math.sqrt(3.0);
        StringBuilder sb = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            st = new StringTokenizer(br.readLine());
            long i = Long.parseLong(st.nextToken());
            long k = Long.parseLong(st.nextToken());
            long s = Long.parseLong(st.nextToken());
            st = new StringTokenizer(br.readLine());
            double a_i = Double.parseDouble(st.nextToken());
            double b_i = Double.parseDouble(st.nextToken());
            long diff = k - i;
            double a_k = a_i * Math.pow(SQRT2, (double)diff);
            double b_k = b_i * Math.pow(SQRT3, (double)diff);
            double Q = (a_k + b_k) / Math.pow(2.0, (double)s);
            sb.append(String.format(java.util.Locale.US, "%.5f", Q)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

